'use client'
import { useState } from 'react'
import { useAuthStore } from '../../../store/authStore'
import Card from '../../../components/ui/Card'
import Button from '../../../components/ui/Button'
import Input from '../../../components/ui/Input'
import { User, Shield, Edit2, Save } from 'lucide-react'
import { ARMY_RANKS, INDIAN_STATES } from '../../../lib/constants'

export default function ProfilePage() {
  const { user } = useAuthStore()
  const [editing, setEditing] = useState(false)
  const [saved,   setSaved]   = useState(false)

  const [form, setForm] = useState({
    full_name:      user?.full_name ?? '',
    email:          user?.email    ?? '',
    phone:          '',
    rank:           '',
    regiment:       '',
    service_number: '',
    date_of_birth:  '',
    date_of_discharge: '',
    pension_number: '',
    echs_card_number: '',
    address:        '',
    state:          '',
  })

  async function handleSave() {
    // Will connect to API later
    setSaved(true)
    setEditing(false)
    setTimeout(() => setSaved(false), 3000)
  }

  return (
    <div className="space-y-6 max-w-3xl">

      {/* Page header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">My Profile</h1>
          <p className="text-gray-500 text-sm mt-1">
            Your personal and service details
          </p>
        </div>
        <Button
          variant={editing ? 'primary' : 'outline'}
          onClick={editing ? handleSave : () => setEditing(true)}
          size="md"
        >
          {editing ? (
            <><Save size={16} className="mr-2" /> Save Changes</>
          ) : (
            <><Edit2 size={16} className="mr-2" /> Edit Profile</>
          )}
        </Button>
      </div>

      {saved && (
        <div className="p-3 bg-green-50 border border-green-200 rounded-lg text-sm text-green-700">
          ✅ Profile saved successfully!
        </div>
      )}

      {/* Avatar card */}
      <Card padding="md">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-green-700 rounded-2xl flex items-center justify-center">
            <span className="text-white text-2xl font-bold">
              {user?.full_name?.charAt(0).toUpperCase() ?? 'V'}
            </span>
          </div>
          <div>
            <h2 className="text-xl font-bold text-gray-900">{user?.full_name}</h2>
            <p className="text-gray-500 text-sm">{user?.email}</p>
            <span className="inline-flex items-center gap-1 mt-1 text-xs text-green-700 font-medium">
              <Shield size={12} /> Verified Veteran
            </span>
          </div>
        </div>
      </Card>

      {/* Personal details */}
      <Card padding="md">
        <h3 className="text-base font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <User size={18} className="text-green-700" />
          Personal Information
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Input
            label="Full Name"
            value={form.full_name}
            disabled={!editing}
            onChange={(e) => setForm({ ...form, full_name: e.target.value })}
          />
          <Input
            label="Email Address"
            value={form.email}
            disabled={true}
            hint="Email cannot be changed"
          />
          <Input
            label="Phone Number"
            value={form.phone}
            placeholder="+91 XXXXX XXXXX"
            disabled={!editing}
            onChange={(e) => setForm({ ...form, phone: e.target.value })}
          />
          <Input
            label="Date of Birth"
            type="date"
            value={form.date_of_birth}
            disabled={!editing}
            onChange={(e) => setForm({ ...form, date_of_birth: e.target.value })}
          />
          <div className="sm:col-span-2">
            <Input
              label="Address"
              value={form.address}
              placeholder="Full residential address"
              disabled={!editing}
              onChange={(e) => setForm({ ...form, address: e.target.value })}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1.5">State</label>
            <select
              value={form.state}
              disabled={!editing}
              onChange={(e) => setForm({ ...form, state: e.target.value })}
              className="w-full px-4 py-2.5 rounded-lg border border-gray-300 text-sm focus:outline-none focus:ring-2 focus:ring-green-500 bg-white disabled:bg-gray-50 disabled:text-gray-500"
            >
              <option value="">Select state</option>
              {INDIAN_STATES.map((s) => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          </div>
        </div>
      </Card>

      {/* Service details */}
      <Card padding="md">
        <h3 className="text-base font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <Shield size={18} className="text-green-700" />
          Service Details
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Input
            label="Service Number"
            value={form.service_number}
            placeholder="e.g. 15701234P"
            disabled={!editing}
            onChange={(e) => setForm({ ...form, service_number: e.target.value })}
          />
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1.5">Rank</label>
            <select
              value={form.rank}
              disabled={!editing}
              onChange={(e) => setForm({ ...form, rank: e.target.value })}
              className="w-full px-4 py-2.5 rounded-lg border border-gray-300 text-sm focus:outline-none focus:ring-2 focus:ring-green-500 bg-white disabled:bg-gray-50 disabled:text-gray-500"
            >
              <option value="">Select rank</option>
              {ARMY_RANKS.map((r) => (
                <option key={r} value={r}>{r}</option>
              ))}
            </select>
          </div>
          <Input
            label="Regiment / Unit"
            value={form.regiment}
            placeholder="e.g. 3rd Battalion, Rajput Regiment"
            disabled={!editing}
            onChange={(e) => setForm({ ...form, regiment: e.target.value })}
          />
          <Input
            label="Date of Discharge"
            type="date"
            value={form.date_of_discharge}
            disabled={!editing}
            onChange={(e) => setForm({ ...form, date_of_discharge: e.target.value })}
          />
          <Input
            label="Pension PPO Number"
            value={form.pension_number}
            placeholder="e.g. S/2024/12345"
            disabled={!editing}
            onChange={(e) => setForm({ ...form, pension_number: e.target.value })}
          />
          <Input
            label="ECHS Card Number"
            value={form.echs_card_number}
            placeholder="e.g. ECHS-1234567"
            disabled={!editing}
            onChange={(e) => setForm({ ...form, echs_card_number: e.target.value })}
          />
        </div>
      </Card>

    </div>
  )
}